import json
import math
import os
from concurrent.futures import ThreadPoolExecutor, as_completed
from datetime import datetime, timedelta, timezone
from urllib.parse import urlencode
from urllib.request import Request, urlopen


def synthetic_bars(pair, days=260):
    seed = sum(ord(c) for c in pair)
    price = 1.0 + (seed % 70) / 100.0
    if pair.endswith("JPY"):
        price = 100.0 + (seed % 60)
    bars = []
    now = datetime.now(timezone.utc)
    for i in range(days):
        t = now - timedelta(days=days - i)
        drift = math.sin((i + seed) / 17.0) * 0.002
        price = max(0.0001, price * (1.0 + drift / 10.0))
        spread = price * (0.0015 + abs(math.sin(i / 9.0)) * 0.001)
        bars.append({
            "t": t.isoformat().replace("+00:00", "Z"),
            "o": price - spread / 3,
            "h": price + spread,
            "l": price - spread,
            "c": price,
            "v": 0,
        })
    return bars


def fetch_one(j):
    pair = j.get("pair")
    symbol = j.get("symbol_yf") or f"{pair}=X"
    dry_run = bool(j.get("dry_run")) or os.getenv("AG1_FX_DRY_RUN") == "1"
    try:
        if dry_run:
            payload = {"ok": True, "symbol": symbol, "source": "synthetic", "bars": synthetic_bars(pair)}
        else:
            base = str(j.get("yfinance_api_base") or "http://yfinance-api:8080").rstrip("/")
            params = {
                "symbol": symbol,
                "interval": j.get("interval") or "1d",
                "lookback_days": int(j.get("lookback_days") or 420),
                "max_bars": int(j.get("max_bars") or 420),
                "allow_stale": "true",
            }
            url = f"{base}/history?{urlencode(params)}"
            req = Request(url, headers={"Accept": "application/json"})
            # urlopen raises HTTPError automatically on 4xx/5xx (caught by outer except).
            with urlopen(req, timeout=30) as resp:
                body = resp.read()
            payload = json.loads(body.decode("utf-8"))
        return {"json": {**j, "history": payload, "fetch_error": ""}}
    except Exception as exc:
        return {"json": {**j, "history": {"ok": False, "bars": []}, "fetch_error": str(exc)}}


items = _items or []
out = [None] * len(items)
if items:
    with ThreadPoolExecutor(max_workers=8) as pool:
        futures = {
            pool.submit(fetch_one, it.get("json", {}) or {}): idx
            for idx, it in enumerate(items)
        }
        for fut in as_completed(futures):
            idx = futures[fut]
            out[idx] = fut.result()

return out

out = []
for it in _items or []:
    j = it.get("json", {}) or {}
    close = j.get("last_close")
    sma20 = j.get("sma20")
    sma50 = j.get("sma50")
    sma200 = j.get("sma200")
    bw = j.get("bb_width")
    regime = "range"
    if close is not None and sma50 is not None and sma200 is not None:
        if close > sma50 > sma200:
            regime = "trend_up"
        elif close < sma50 < sma200:
            regime = "trend_down"
    if bw is not None and bw > 0.06 and sma20 is not None and close is not None:
        regime = "breakout"
    out.append({"json": {**j, "regime": regime}})

return out

def clamp(v, lo=-1.0, hi=1.0):
    return max(lo, min(hi, v))


out = []
for it in _items or []:
    j = it.get("json", {}) or {}
    score = 0.0
    close = j.get("last_close")
    for key, weight in [("ret_5d", 0.20), ("ret_20d", 0.25), ("macd_hist", 0.20)]:
        v = j.get(key)
        if v is not None:
            score += weight if float(v) > 0 else -weight
    rsi = j.get("rsi14")
    if rsi is not None:
        r = float(rsi)
        if r < 30:
            score += 0.20
        elif r > 70:
            score -= 0.20
        elif 45 <= r <= 60:
            score += 0.05
    if close is not None and j.get("sma50") is not None:
        score += 0.20 if float(close) > float(j["sma50"]) else -0.20
    score = clamp(score)
    if score >= 0.65:
        label = "strong_buy"
    elif score >= 0.25:
        label = "buy"
    elif score <= -0.65:
        label = "strong_sell"
    elif score <= -0.25:
        label = "sell"
    else:
        label = "neutral"
    out.append({"json": {**j, "signal_score": score, "signal_label": label}})

return out
